 1	import type { FC, ReactNode } from 'react';
 2	
 3	import { Button, ButtonVariant, Grid, Split, SplitItem } from '@patternfly/react-core';
 4	import { PlusCircleIcon } from '@patternfly/react-icons';
 5	import { useForkliftTranslation } from '@utils/i18n';
 6	
 7	type LabelsListProps = {
 8	  addRowText?: string;
 9	  children: ReactNode;
10	  emptyStateAddRowText?: string;
11	  isEmpty: boolean;
12	  onLabelAdd: () => void;
13	  testId?: string;
14	};
15	
16	const LabelsList: FC<LabelsListProps> = ({
17	  addRowText = null,
18	  children,
19	  emptyStateAddRowText = null,
20	  isEmpty,
21	  onLabelAdd,
22	  testId,
23	}) => {
24	  const { t } = useForkliftTranslation();
25	
26	  const addRowTxt = addRowText ?? t('Add Label');
27	  const emptyStateAddRowTxt = emptyStateAddRowText ?? t('Add Label to specify qualifying nodes');
28	  return (
29	    <>
30	      <Grid hasGutter>{children}</Grid>
31	      <Split>
32	        <SplitItem>
33	          <Button
34	            className="pf-m-link--align-left"
35	            data-testid={testId}
36	            icon={<PlusCircleIcon />}
37	            onClick={() => {
38	              onLabelAdd();
39	            }}
40	            variant={ButtonVariant.link}
41	          >
42	            {isEmpty ? emptyStateAddRowTxt : addRowTxt}
43	          </Button>
44	        </SplitItem>
45	        <SplitItem isFilled />
46	      </Split>
47	    </>
48	  );
49	};
50	
51	export default LabelsList;

